import type { PersonaMemoryRecord, PersonaMemorySourceType } from '@/shared/contracts/persona-memory';
import {
  asRecord,
  toIsoString,
  truncateText,
  extractTopicHints,
  normalizeMoodHints,
} from './persona-memory-utils';
import type { PersonaMemoryEntryRecord, PersonaConversationMessageRecord } from './persona-memory-types';

const resolveRole = (metadata: Record<string, unknown> | undefined): string | null => {
  if (typeof metadata?.['role'] === 'string') return metadata['role'];
  if (typeof metadata?.['originRole'] === 'string') return metadata['originRole'];
  return null;
};

const resolveSourceCreatedAt = (
  item: PersonaMemoryEntryRecord,
  metadata: Record<string, unknown> | undefined
): string | null => {
  const sourceCreatedAtStr = toIsoString(item.sourceCreatedAt);
  if (sourceCreatedAtStr !== null) return sourceCreatedAtStr;

  const metadataSourceCreatedAt = metadata?.['sourceCreatedAt'];
  return typeof metadataSourceCreatedAt === 'string' ? metadataSourceCreatedAt : null;
};

const resolveTitle = (item: PersonaMemoryEntryRecord): string => {
  if (item.sourceLabel !== null) return item.sourceLabel;
  if (item.summary !== null) return item.summary;
  return truncateText(item.content, 80);
};

const resolveSessionId = (metadata: Record<string, unknown> | undefined, runId: string | null): string | null => {
  if (typeof metadata?.['sessionId'] === 'string') return metadata['sessionId'];
  return runId;
};

const resolveTopicHints = (item: PersonaMemoryEntryRecord): string[] => {
  return extractTopicHints(item.summary ?? item.content, item.topicHints);
};

const resolveMoodHints = (item: PersonaMemoryEntryRecord): string[] => {
  return normalizeMoodHints(item.moodHints, item.summary ?? item.content);
};

export const mapMemoryEntryToRecord = (
  item: PersonaMemoryEntryRecord,
  personaId: string
): PersonaMemoryRecord => {
  const metadata = asRecord(item.metadata);
  const lastAccessedAt = item.lastAccessedAt !== null ? toIsoString(item.lastAccessedAt) : null;

  return {
    id: item.id,
    createdAt: toIsoString(item.createdAt) ?? new Date().toISOString(),
    updatedAt: toIsoString(item.updatedAt) ?? new Date().toISOString(),
    personaId,
    recordType: 'memory_entry',
    content: item.content,
    summary: item.summary,
    title: resolveTitle(item),
    role: resolveRole(metadata),
    sessionId: resolveSessionId(metadata, item.runId),
    memoryKey: item.memoryKey,
    sourceType: (item.sourceType ?? 'agent_memory') as PersonaMemorySourceType,
    sourceId: item.sourceId ?? item.id,
    sourceLabel: item.sourceLabel,
    sourceCreatedAt: resolveSourceCreatedAt(item, metadata),
    importance: item.importance,
    tags: item.tags,
    topicHints: resolveTopicHints(item),
    moodHints: resolveMoodHints(item),
    metadata: {
      ...(metadata ?? {}),
      ...(item.runId !== null ? { runId: item.runId } : {}),
      ...(lastAccessedAt !== null ? { lastAccessedAt } : {}),
    },
  };
};

const resolveConversationMoodHints = (message: PersonaConversationMessageRecord, metadata: Record<string, unknown> | undefined): string[] => {
  const rawMoodHints = metadata?.['moodHints'];
  return normalizeMoodHints(
    Array.isArray(rawMoodHints)
      ? rawMoodHints.filter((item): item is string => typeof item === 'string')
      : [],
    message.content
  );
};

export const mapConversationMessageToRecord = (
  message: PersonaConversationMessageRecord,
  personaId: string
): PersonaMemoryRecord => {
  const metadata = asRecord(message.metadata);

  return {
    id: message.id,
    createdAt: toIsoString(message.createdAt) ?? new Date().toISOString(),
    updatedAt: toIsoString(message.createdAt) ?? new Date().toISOString(),
    personaId,
    recordType: 'conversation_message',
    content: message.content,
    summary: truncateText(message.content, 140),
    title: `${message.role === 'assistant' ? 'Assistant' : 'User'} message`,
    role: message.role,
    sessionId: message.sessionId,
    memoryKey: null,
    sourceType: 'chat_message',
    sourceId: message.id,
    sourceLabel: message.session.title ?? 'Untitled session',
    sourceCreatedAt: toIsoString(message.createdAt),
    importance: null,
    tags: [],
    topicHints: extractTopicHints(message.content),
    moodHints: resolveConversationMoodHints(message, metadata),
    metadata: {
      ...(metadata ?? {}),
      sessionTitle: message.session.title,
      ...(message.model !== null ? { model: message.model } : {}),
      ...(message.images.length > 0 ? { images: message.images } : {}),
    },
  };
};

import { addAgentLongTermMemory } from '@/features/ai/agent-runtime/memory';
import type { AgentPersonaMoodId } from '@/shared/contracts/agents';
import type { PersonaMemorySourceType } from '@/shared/contracts/persona-memory';
import {
  uniqueStrings,
  extractTopicHints,
  normalizeMoodHints,
  truncateText,
} from './persona-memory-utils';
import { buildAgentPersonaMemoryKey } from './persona-memory';

export type PersistAgentPersonaExchangeMemoryParams = {
  personaId: string;
  sourceType: PersonaMemorySourceType;
  sourceId: string;
  sourceLabel?: string | null;
  sourceCreatedAt?: string | Date | null;
  sessionId?: string | null;
  userMessage?: string | null;
  assistantMessage: string;
  tags?: string[];
  topicHints?: string[];
  moodHints?: AgentPersonaMoodId[];
  metadata?: Record<string, unknown>;
};

function resolveTopicHints(userMessage: string, assistantMessage: string, providedTopicHints?: string[]): string[] {
  const combinedText = [userMessage, assistantMessage].filter((part) => part !== '').join('\n');
  return uniqueStrings([
    ...(providedTopicHints ?? []),
    ...extractTopicHints(combinedText),
  ]).slice(0, 6);
}

function resolveMoodHints(assistantMessage: string, providedMoodHints?: AgentPersonaMoodId[]): AgentPersonaMoodId[] {
  const inferredMoodHints = normalizeMoodHints(providedMoodHints ?? [], assistantMessage);
  return Array.from(new Set([...(providedMoodHints ?? []), ...inferredMoodHints]));
}

function resolveTags(sourceType: string, providedTags?: string[]): string[] {
  return uniqueStrings([
    'persona-memory',
    sourceType,
    ...(providedTags ?? []),
  ]);
}

function resolveContent(userMessage: string, assistantMessage: string): string {
  return userMessage !== ''
    ? `User: ${userMessage}\nAssistant: ${assistantMessage}`
    : `Assistant: ${assistantMessage}`;
}

function resolveSummary(userMessage: string, assistantMessage: string): string {
  return userMessage !== ''
    ? `User asked: ${truncateText(userMessage, 90)} Assistant replied: ${truncateText(assistantMessage, 120)}`
    : truncateText(assistantMessage, 180);
}

export async function persistAgentPersonaExchangeMemory(
  params: PersistAgentPersonaExchangeMemoryParams
): Promise<void> {
  const personaId = params.personaId.trim();
  const assistantMessage = params.assistantMessage.trim();
  const userMessage = (params.userMessage ?? '').trim();

  if (personaId === '' || assistantMessage === '') {
    return;
  }

  await addAgentLongTermMemory({
    memoryKey: buildAgentPersonaMemoryKey(personaId),
    personaId,
    content: resolveContent(userMessage, assistantMessage),
    summary: resolveSummary(userMessage, assistantMessage),
    tags: resolveTags(params.sourceType, params.tags),
    topicHints: resolveTopicHints(userMessage, assistantMessage, params.topicHints),
    moodHints: resolveMoodHints(assistantMessage, params.moodHints),
    sourceType: params.sourceType,
    sourceId: params.sourceId,
    sourceLabel: params.sourceLabel ?? null,
    sourceCreatedAt: params.sourceCreatedAt ?? null,
    metadata: {
      ...(params.metadata ?? {}),
      ...(params.sessionId !== undefined && params.sessionId !== null ? { sessionId: params.sessionId } : {}),
      originRole: 'assistant',
      ...(userMessage !== '' ? { latestUserMessage: userMessage } : {}),
    },
    importance: params.sourceType === 'chat_message' ? 2 : 3,
  });
}

import type { AgentPersonaMoodId } from '@/shared/contracts/agents';
import type { PersonaMemoryRecord } from '@/shared/contracts/persona-memory';
import {
  uniqueLowercaseStrings,
  matchesExactOrPartial,
} from './persona-memory-utils';

export const buildRecordSearchHaystacks = (item: PersonaMemoryRecord): string[] =>
  uniqueLowercaseStrings([
    item.content,
    item.summary ?? null,
    item.title ?? null,
    item.sourceLabel ?? null,
    item.role ?? null,
    ...item.tags,
    ...item.topicHints,
    ...item.moodHints,
  ]);

export const countMatchingSearchTerms = (item: PersonaMemoryRecord, searchTerms: string[]): number => {
  if (searchTerms.length === 0) {
    return 0;
  }

  const haystacks = buildRecordSearchHaystacks(item);
  return searchTerms.filter((term) => haystacks.some((value) => value.includes(term))).length;
};

export const matchesPersonaMemoryRecord = (
  item: PersonaMemoryRecord,
  filters: {
    tag: string | null;
    topic: string | null;
    mood: AgentPersonaMoodId | null;
    searchTerms: string[];
  }
): boolean => {
  const normalizedTags = uniqueLowercaseStrings(item.tags);

  if (filters.tag !== null && !matchesExactOrPartial(normalizedTags, filters.tag)) {
    return false;
  }

  if (filters.topic !== null && !matchesExactOrPartial(item.topicHints, filters.topic)) {
    return false;
  }

  if (filters.mood !== null && !item.moodHints.includes(filters.mood)) {
    return false;
  }

  if (filters.searchTerms.length > 0 && countMatchingSearchTerms(item, filters.searchTerms) === 0) {
    return false;
  }

  return true;
};

export const scorePersonaMemoryRecord = (
  item: PersonaMemoryRecord,
  filters: {
    tag: string | null;
    topic: string | null;
    mood: AgentPersonaMoodId | null;
    searchTerms: string[];
  }
): number => {
  const termScore = countMatchingSearchTerms(item, filters.searchTerms) * 10;
  const tagScore = (filters.tag !== null && matchesExactOrPartial(item.tags, filters.tag)) ? 8 : 0;
  const topicScore = (filters.topic !== null && matchesExactOrPartial(item.topicHints, filters.topic)) ? 12 : 0;
  const moodScore = (filters.mood !== null && item.moodHints.includes(filters.mood)) ? 10 : 0;
  const typeScore = item.recordType === 'memory_entry' ? 1 : 0;

  return termScore + tagScore + topicScore + moodScore + typeScore;
};

import {
  getAgentLongTermMemoryDelegate,
  getChatbotMessageDelegate,
} from '@/features/ai/agent-runtime/store-delegates';
import { buildAgentPersonaSettings } from '@/features/ai/agentcreator/utils/personas';
import type {
  AgentPersonaMoodId,
} from '@/shared/contracts/agents';
import type {
  PersonaMemoryRecord,
  PersonaMemorySearchResponse,
  PersonaMemorySourceType,
} from '@/shared/contracts/persona-memory';

import {
  clamp,
  countSuggestedMood,
  resolveSourceTypeFilter,
  buildSearchTerms,
  normalizeTopicFilter,
  toTimestamp,
} from './persona-memory-utils';
import {
  matchesPersonaMemoryRecord,
  scorePersonaMemoryRecord,
} from './persona-memory-scoring';
import {
  mapMemoryEntryToRecord,
  mapConversationMessageToRecord,
} from './persona-memory-mappers';
import type {
  PersonaMemoryEntryRecord,
  PersonaConversationMessageRecord,
} from './persona-memory-types';
import { getAgentPersonaById } from './persona-memory';

export type SearchAgentPersonaMemoryParams = {
  personaId: string;
  q?: string | null;
  tag?: string | null;
  topic?: string | null;
  mood?: AgentPersonaMoodId | null;
  sourceType?: PersonaMemorySourceType | null;
  limit?: number;
};

function buildMemoryQuery(params: {
  personaId: string;
  sourceType: string | null;
  tag: string | null;
  topic: string | null;
  mood: string | null;
  searchTerms: string[];
  take: number;
}): Record<string, unknown> {
  return {
    where: {
      personaId: params.personaId,
      ...(params.sourceType !== null ? { sourceType: params.sourceType } : {}),
      ...(params.tag !== null ? { tags: { has: params.tag } } : {}),
      ...(params.topic !== null ? { topicHints: { has: params.topic } } : {}),
      ...(params.mood !== null ? { moodHints: { has: params.mood } } : {}),
      ...(params.searchTerms.length > 0
        ? {
          OR: params.searchTerms.flatMap((term) => [
            { content: { contains: term, mode: 'insensitive' as const } },
            { summary: { contains: term, mode: 'insensitive' as const } },
            { sourceLabel: { contains: term, mode: 'insensitive' as const } },
            { tags: { has: term } },
            { topicHints: { has: term } },
          ]),
        }
        : {}),
    },
    orderBy: { updatedAt: 'desc' as const },
    take: params.take,
  };
}

function buildMessageQuery(params: {
  personaId: string;
  searchTerms: string[];
  take: number;
}): Record<string, unknown> {
  return {
    where: {
      session: { personaId: params.personaId },
      ...(params.searchTerms.length > 0
        ? {
          OR: params.searchTerms.flatMap((term) => [
            { content: { contains: term, mode: 'insensitive' as const } },
            {
              session: {
                title: { contains: term, mode: 'insensitive' as const },
              },
            },
          ]),
        }
        : {}),
    },
    include: {
      session: {
        select: {
          id: true,
          title: true,
          createdAt: true,
          updatedAt: true,
        },
      },
    },
    orderBy: { createdAt: 'desc' as const },
    take: params.take,
  };
}

function normalizeSearchParams(params: SearchAgentPersonaMemoryParams): {
  searchQuery: string | null;
  tag: string | null;
  topic: string | null;
  mood: AgentPersonaMoodId | null;
  sourceType: PersonaMemorySourceType | null;
  searchTerms: string[];
} {
  const rawQ = params.q;
  const searchQuery = rawQ !== null && rawQ !== undefined ? rawQ.trim() : null;
  const rawTag = params.tag;
  const tag = rawTag !== null && rawTag !== undefined ? rawTag.trim() : null;

  return {
    searchQuery,
    tag,
    topic: normalizeTopicFilter(params.topic),
    mood: params.mood ?? null,
    sourceType: params.sourceType ?? null,
    searchTerms: buildSearchTerms(searchQuery),
  };
}

function processMemoryResults(
  memoryEntries: PersonaMemoryEntryRecord[],
  conversationMessages: PersonaConversationMessageRecord[],
  personaId: string,
  params: {
    tag: string | null;
    topic: string | null;
    mood: AgentPersonaMoodId | null;
    searchTerms: string[];
    limit: number;
  }
): PersonaMemoryRecord[] {
  const memoryItems = memoryEntries.map((item) => mapMemoryEntryToRecord(item, personaId));
  const messageItems = conversationMessages.map((message) => mapConversationMessageToRecord(message, personaId));

  return [...memoryItems, ...messageItems]
    .filter((item) => matchesPersonaMemoryRecord(item, params))
    .sort((left, right) => {
      const scoreDelta =
        scorePersonaMemoryRecord(right, params) -
        scorePersonaMemoryRecord(left, params);
      return scoreDelta !== 0 ? scoreDelta : toTimestamp(right.updatedAt) - toTimestamp(left.updatedAt);
    })
    .slice(0, params.limit);
}

function resolveCandidateLimit(limit: number, hasFilter: boolean): number {
  return hasFilter ? clamp(limit * 4, limit, 200, limit) : limit;
}

async function fetchMemoryEntries(params: {
  personaId: string;
  sourceType: PersonaMemorySourceType | null;
  tag: string | null;
  topic: string | null;
  mood: AgentPersonaMoodId | null;
  searchTerms: string[];
  take: number;
  enabled: boolean;
}): Promise<PersonaMemoryEntryRecord[]> {
  const agentLongTermMemory = getAgentLongTermMemoryDelegate();
  if (!params.enabled || agentLongTermMemory === null) {
    return [];
  }

  return agentLongTermMemory.findMany<PersonaMemoryEntryRecord>(buildMemoryQuery({
    personaId: params.personaId,
    sourceType: params.sourceType,
    tag: params.tag,
    topic: params.topic,
    mood: params.mood,
    searchTerms: params.searchTerms,
    take: params.take,
  }));
}

async function fetchConversationMessages(params: {
  personaId: string;
  searchTerms: string[];
  take: number;
  enabled: boolean;
}): Promise<PersonaConversationMessageRecord[]> {
  const chatbotMessage = getChatbotMessageDelegate();
  if (!params.enabled || chatbotMessage === null) {
    return [];
  }

  return chatbotMessage.findMany<PersonaConversationMessageRecord>(buildMessageQuery({
    personaId: params.personaId,
    searchTerms: params.searchTerms,
    take: params.take,
  }));
}

async function updateLastAccessedAt(memoryEntries: PersonaMemoryEntryRecord[]): Promise<void> {
  const agentLongTermMemory = getAgentLongTermMemoryDelegate();
  if (memoryEntries.length === 0 || agentLongTermMemory === null) {
    return;
  }

  await agentLongTermMemory.updateMany({
    where: { id: { in: memoryEntries.map((item) => item.id) } },
    data: { lastAccessedAt: new Date() },
  });
}

export async function searchAgentPersonaMemory(
  params: SearchAgentPersonaMemoryParams
): Promise<PersonaMemorySearchResponse> {
  const personaId = params.personaId;
  const persona = await getAgentPersonaById(personaId);
  if (persona === null) {
    throw new Error(`Agent persona "${personaId}" was not found.`);
  }

  const settings = buildAgentPersonaSettings(persona.settings);
  const memorySettings = settings.memory ?? {};
  const limit = clamp(params.limit, 1, 100, memorySettings.defaultSearchLimit ?? 20);

  const normalized = normalizeSearchParams(params);
  const { allowMessages, allowMemoryEntries } = resolveSourceTypeFilter(normalized.sourceType);

  const hasFilter = normalized.searchTerms.length > 0 || normalized.tag !== null || normalized.topic !== null || normalized.mood !== null;
  const candidateLimit = resolveCandidateLimit(limit, hasFilter);

  const [memoryEntries, conversationMessages] = await Promise.all([
    fetchMemoryEntries({
      ...normalized,
      personaId,
      take: candidateLimit,
      enabled: allowMemoryEntries && memorySettings.enabled !== false,
    }),
    fetchConversationMessages({
      personaId,
      searchTerms: normalized.searchTerms,
      take: candidateLimit,
      enabled: allowMessages && memorySettings.includeChatHistory !== false && normalized.tag === null,
    }),
  ]);

  await updateLastAccessedAt(memoryEntries);

  const items = processMemoryResults(memoryEntries, conversationMessages, personaId, {
    ...normalized,
    limit,
  });

  return {
    items,
    summary: {
      personaId,
      suggestedMoodId: memorySettings.useMoodSignals === false ? null : countSuggestedMood(items),
      totalRecords: items.length,
      memoryEntryCount: items.filter((item) => item.recordType === 'memory_entry').length,
      conversationMessageCount: items.filter((item) => item.recordType === 'conversation_message').length,
    },
  };
}
